class ImageDataset(Dataset):
    def __init__(self, data, transform=None):
        self.data = data
        self.transform = transform

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        image_path, label = self.data[idx]
        image = Image.open(image_path).convert('RGB')
        if self.transform:
            image = self.transform(image)
        return image, label

class SimpleCNN(nn.Module):
    def __init__(self, num_classes=NUM_CLASSES):
        super(SimpleCNN, self).__init__()
        self.features = nn.Sequential(
            nn.Conv2d(3, 32, kernel_size=3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2),
            nn.Conv2d(32, 64, kernel_size=3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(kernel_size=2, stride=2),
        )
        self.classifier = nn.Sequential(
            nn.Dropout(),
            nn.Linear(64 * 8 * 8, 512),
            nn.ReLU(inplace=True),
            nn.Linear(512, num_classes)
        )

    def forward(self, x):
        x = self.features(x)
        x = x.view(x.size(0), -1)
        x = self.classifier(x)
        return x

def calculate_consensus_label(labels: List[Dict]) -> Tuple[int, float]:
    """Calculate consensus label using majority voting with confidence"""
    label_votes = Counter([label['label'] for label in labels])
    max_votes = max(label_votes.values())
    consensus_label = label_votes.most_common(1)[0][0]
    
    # Calculate confidence as ratio of votes to total
    confidence = max_votes / len(labels)
    
    return consensus_label, confidence

def validate_label(label_data: Dict) -> bool:
    """Validate label data and prevent label flipping"""
    required_fields = ['image_id', 'label', 'annotator_id']
    if not all(field in label_data for field in required_fields):
        return False
    
    # Check if label is within valid range
    if not (0 <= label_data['label'] < NUM_CLASSES):
        return False
    
    # Generate hash to prevent tampering
    data_string = f"{label_data['image_id']}{label_data['label']}{label_data['annotator_id']}{SECURE_SALT}"
    expected_hash = hashlib.sha256(data_string.encode()).hexdigest()
    
    if 'hash' in label_data and label_data['hash'] != expected_hash:
        logger.warning(f"Label hash mismatch for image {label_data['image_id']}")
        return False
    
    return True

def update_annotator_score(annotator_id: str, is_correct: bool):
    """Update annotator score based on accuracy"""
    if is_correct:
        annotator_scores[annotator_id] += 0.1
    else:
        annotator_scores[annotator_id] -= 0.1
    annotator_scores[annotator_id] = max(0, annotator_scores[annotator_id])

def get_annotator_weight(annotator_id: str) -> float:
    """Get weight for annotator based on score"""
    return max(0.1, annotator_scores[annotator_id] / 10.0)

