@app.route('/aggregate/<image_id>', methods=['GET'])
def get_aggregated_label(image_id: str):
    """Get aggregated label for an image"""
    if image_id not in image_labels:
        return jsonify({'error': 'No labels found for this image'}), 404
    
    labels = image_labels[image_id]
    consensus_label, confidence = calculate_consensus_label(labels)
    
    # Calculate weighted average for final label
    weighted_labels = []
    for label_entry in labels:
        weighted_labels.append((label_entry['label'], label_entry['weight']))
    
    final_label = Counter({label: weight for label, weight in weighted_labels}).most_common(1)[0][0]
    
    return jsonify({
        'image_id': image_id,
        'aggregated_label': final_label,
        'confidence': confidence,
        'total_votes': len(labels),
        'annotators': len(set([l['annotator_id'] for l in labels]))
    })

@app.route('/train', methods=['POST'])
def train_model():
    """Train model on labeled data"""
    try:
        # Prepare training data
        train_data = []
        for image_id, labels in image_labels.items():
            if len(labels) >= 2:  # Only use images with multiple labels
                consensus_label, _ = calculate_consensus_label(labels)
                # In a real system, you'd have actual image paths
                train_data.append((f"images/{image_id}.jpg", consensus_label))
        
        if len(train_data) < 10:
            return jsonify({'error': 'Not enough labeled data for training'}), 400
        
        # Transformations
        transform = transforms.Compose([
            transforms.Resize((32, 32)),
            transforms.ToTensor(),
            transforms.Normalize((0.5, 0.5, 0.5), (0.5, 0.5, 0.5))
        ])
        
        # Create dataset and dataloader
        dataset = ImageDataset(train_data, transform=transform)
        dataloader = DataLoader(dataset, batch_size=BATCH_SIZE, shuffle=True)
        
        # Initialize model
        model = SimpleCNN(num_classes=NUM_CLASSES)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)
        
        # Training loop
        model.train()
        for epoch in range(NUM_EPOCHS):
            running_loss = 0.0
            for images, labels in dataloader:
                optimizer.zero_grad()
                outputs = model(images)
                loss = criterion(outputs, labels)
                loss.backward()
                optimizer.step()
                running_loss += loss.item()
            
            logger.info(f'Epoch [{epoch+1}/{NUM_EPOCHS}], Loss: {running_loss/len(dataloader):.4f}')
        
        # Save model weights
        model_weights['latest'] = {
            'model_state_dict': model.state_dict(),
            'training_timestamp': datetime.utcnow().isoformat(),
            'num_samples': len(train_data)
        }
        
        return jsonify({
            'status': 'success',
            'message': 'Model trained successfully',
            'samples_used': len(train_data),
            'epochs': NUM_EPOCHS
        })
    
    except Exception as e:
        logger.error(f"Error training model: {str(e)}")
        return jsonify({'error': 'Model training failed'}), 500

